                result["data"]["rank"] = int(valid_nums[0])
                result["data"]["count"] = float(valid_nums[1])
                result["data"]["faculty"] = int(valid_nums[2])

        # Alternative: search table rows
        if result["data"]["rank"] is None:
            rows = page.query_selector_all("tr")
            for row in rows:
                try:
                    text = row.inner_text()
                    if "Shanghai" in text and "Jiao" in text:
                        cells = row.query_selector_all("td")
                        cell_texts = [c.inner_text().strip() for c in cells]

                        nums = []
                        for ct in cell_texts:
                            num_match = re.search(r'^(\d+(?:\.\d+)?)$', ct)
