    page.select_option("#regions", "world")
    page.select_option("#fromyear", "2020")
    page.select_option("#toyear", "2025")

    try:
        page.locator("#all_areas_off").first.click()
    except:
        pass

    # Click AI areas
    for area in ["Artificial intelligence", "Computer vision", "Machine learning",
                 "Natural language processing", "The Web & Information retrieval"]:
        try:
            page.get_by_text(area, exact=False).first.click()
        except:
            pass

    page.wait_for_timeout(5000)

    # Extract
    data = page.evaluate("""() => {
        for (const a of document.querySelectorAll('a')) {
            if (/shanghai.*jiao.*tong|shanghai.*jiaotong/i.test(a.textContent)) {
                const row = a.closest('tr');
                if (row) {
                    const nums = [];
                    row.querySelectorAll('td').forEach(td => {
                        const t = td.textContent.trim();
                        if (/^\\d+(\\.\\d+)?$/.test(t)) nums.push(parseFloat(t));
                    });
                    if (nums.length >= 3) return {rank: nums[0]|0, count: nums[1], faculty: nums[2]|0};
                }
            }
        }
        return null;
    }""")

    result = {
        "final_url": page.url,
        "data": {
            "institution": "Shanghai Jiao Tong University",
            "rank": data["rank"] if data else None,
            "count": data["count"] if data else None,
            "faculty": data["faculty"] if data else None
        }
    }

    browser.close()
    print(json.dumps(result, indent=2))"}

