        # Dismiss any overlay/sponsor popup
        try:
            overlays = page.query_selector_all("#overlay-sponsor, .overlay, .modal")
            for overlay in overlays:
                if overlay.is_visible():
                    overlay.click()
                    page.wait_for_timeout(500)
        except:
            pass

        # Wait for any select element to appear
        page.wait_for_selector("select", timeout=30000)
        page.wait_for_timeout(2000)

        # Get page structure info
        page_info = page.evaluate("""
            () => {
                const info = {
                    selects: [],
                    ids: [],
                    hash: window.location.hash
                };
                document.querySelectorAll('select').forEach(s => {
                    info.selects.push({id: s.id, class: s.className, value: s.value});
                });
                document.querySelectorAll('[id]').forEach(el => {
                    if(el.id) info.ids.push(el.id);
                });
                return info;
            }
        """)

