                break
            except:
                pass

        page.wait_for_timeout(500)

        # Set region to World
        for selector in ["#regions", "select[name='region']"]:
            try:
                page.select_option(selector, "world")
                break
            except:
                pass

        page.wait_for_timeout(1500)

        # Turn all areas off first
        try:
            all_off = page.query_selector("#all_areas_off")
            if all_off and all_off.is_visible():
                all_off.click()
                page.wait_for_timeout(1500)
        except:
            pass

        # Select AI areas
        ai_areas = [
            "Artificial intelligence",
            "Computer vision",
            "Machine learning",
            "Natural language processing",
            "The Web & Information retrieval"
        ]

        for area in ai_areas:
            try:
                elements = page.query_selector_all(f'text="{area}"')
                for elem in elements:
                    if elem.is_visible():
                        elem.click()
                        page.wait_for_timeout(500)
                        break
            except:
                pass

        # Wait for URL hash to update
        page.wait_for_timeout(5000)

        # Get the final URL
        final_url = page.url

        result = {
            "final_url": final_url,
            "data": {
                "institution": "Shanghai Jiao Tong University",
                "rank": None,
                "count": None,
                "faculty": None
            }
        }

        # Get all text content from the page
        page_text = page.inner_text("body")

        # Look for SJTU data in page text
        # Pattern: institution name followed by numbers
        lines = page_text.split('\n')
        sjtu_idx = -1

        for i, line in enumerate(lines):
            if "Shanghai Jiao Tong" in line or "Shanghai Jiaotong" in line:
                sjtu_idx = i
                break

        if sjtu_idx >= 0:
            # Look for numbers in nearby lines
            context = '\n'.join(lines[max(0, sjtu_idx-2):sjtu_idx+10])
            numbers = re.findall(r'\b(\d+(?:\.\d+)?)\b', context)

            # Filter to reasonable values
            valid_nums = []
            for n in numbers:
                try:
                    val = float(n)
                    if val < 10000:  # Reasonable upper bound
                        valid_nums.append(val)
                except:
                    pass

            if len(valid_nums) >= 3:
                result["data"]["rank"] = int(valid_nums[0])
                result["data"]["count"] = float(valid_nums[1])
                result["data"]["faculty"] = int(valid_nums[2])

        # Alternative: search table rows
        if result["data"]["rank"] is None:
            rows = page.query_selector_all("tr")
            for row in rows:
                try:
                    text = row.inner_text()
                    if "Shanghai" in text and "Jiao" in text:
                        cells = row.query_selector_all("td")
                        cell_texts = [c.inner_text().strip() for c in cells]

                        nums = []
                        for ct in cell_texts:
                            num_match = re.search(r'^(\d+(?:\.\d+)?)$', ct)
                            if num_match:
                                nums.append(num_match.group(1))

                        if len(nums) >= 3:
                            result["data"]["rank"] = int(nums[0])
                            result["data"]["count"] = float(nums[1])
                            result["data"]["faculty"] = int(nums[2])
                            break
                except:
                    continue

        browser.close()

        return result


def main():
    """Main entry point - output JSON to stdout."""
    result = extract_sjtu_data()
    print(json.dumps(result, indent=2))


