        page.wait_for_timeout(1000)

        # Set years
        page.select_option("#fromyear", "2020")
        page.select_option("#toyear", "2025")
        page.wait_for_timeout(500)

        # Turn all areas off
        try:
            page.locator("#all_areas_off").first.click()
            page.wait_for_timeout(500)
        except:
            pass

        # Select AI areas one by one
        ai_areas = [
            "Artificial intelligence",
            "Computer vision",
            "Machine learning",
            "Natural language processing",
            "The Web & Information retrieval"
        ]

        for area in ai_areas:
            try:
                page.get_by_text(area, exact=False).first.click()
                page.wait_for_timeout(400)
            except Exception as e:
                pass

        # Wait for data to load
        page.wait_for_timeout(8000)

        result["final_url"] = page.url

        # Get page text
        page_text = page.inner_text("body")

        # Check if we have World data now
        if "Shanghai" in page_text:
            match = re.search(r'Shanghai\s+(?:Jiao\s+Tong|Jiaotong)\s+University', page_text, re.IGNORECASE)
            if match:
                start = max(0, match.start() - 150)
                end = min(len(page_text), match.end() + 300)
                context = page_text[start:end]

                all_nums = re.findall(r'\b(\d+(?:\.\d+)?)\b', context)
                valid_nums = []
                for n in all_nums:
                    try:
                        val = float(n)
                        if 0.1 <= val <= 1000:
                            valid_nums.append(val)
                    except:
                        pass

                if len(valid_nums) >= 3:
                    result["data"]["rank"] = int(valid_nums[0])
                    result["data"]["count"] = valid_nums[1]
                    result["data"]["faculty"] = int(valid_nums[2])

        # JS extraction as fallback
        if result["data"]["rank"] is None:
            extracted = page.evaluate("""
                () => {
                    const links = document.querySelectorAll('a');
                    for (const link of links) {
                        const text = link.textContent || '';
                        if (/shanghai.*(jiao.*tong|jiaotong)/i.test(text)) {
                            const row = link.closest('tr');
                            if (row) {
                                const cells = row.querySelectorAll('td');
                                const nums = [];
                                for (const cell of cells) {
                                    const t = cell.textContent.trim();
                                    if (/^\\d+(\\.\\d+)?$/.test(t)) {
                                        nums.push(parseFloat(t));
                                    }
                                }
                                if (nums.length >= 3) {
                                    return {rank: Math.floor(nums[0]), count: nums[1], faculty: Math.floor(nums[2])};
                                }
                            }
                        }
                    }
                    return null;
                }
            """)

            if extracted:
                result["data"]["rank"] = extracted.get("rank")
                result["data"]["count"] = extracted.get("count")
                result["data"]["faculty"] = extracted.get("faculty")

        browser.close()

    print(json.dumps(result, indent=2))


if __name__ == "__main__":
    main()"}

